import React, { useState } from 'react';
import AdminNavbar from '../components/AdminNavbar';
import AdminSidebar from '../components/AdminSidebar';

const ManageBookings = () => {
  const [bookings, setBookings] = useState([
    { id: 1, user: 'John BR1024', car: 'Toyota Camry', dates: 'May 10 - May 15, 2025', revenue: 300, status: 'Completed' },
    { id: 2, user: 'Nino BR1009', car: 'Honda CR-V', dates: 'Apr 2 - Apr 10, 2025', revenue: 550, status: 'Completed' },
    { id: 3, user: 'Jastine BR1024', car: 'Toyota Wigo', dates: 'Mar 14 - Mar 20, 2025', revenue: 230, status: 'Cancelled' },
    { id: 4, user: 'Nere BR1024', car: 'Toyota Fortuner', dates: 'Jan 20 - Jan 25, 2025', revenue: 220, status: 'Cancelled' },
    { id: 5, user: 'Yensyl BR1024', car: 'Toyota Hilux', dates: 'June 14 - June 19, 2025', revenue: 450, status: 'Returned' },
    { id: 6, user: 'Bryson BR1024', car: 'Toyota Vios', dates: 'Sept 3 - Sept 8, 2025', revenue: 500, status: 'Completed' },
    { id: 7, user: 'Bryson BR1024', car: 'Toyota Vios', dates: 'July 11 - July 17, 2025', revenue: 600, status: 'Returned' },
  ]);

  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [selectedBookings, setSelectedBookings] = useState([]);

  const filteredBookings = bookings.filter(booking => {
    const matchesSearch = booking.user.toLowerCase().includes(searchTerm.toLowerCase()) || 
                         booking.car.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = !statusFilter || booking.status.toLowerCase() === statusFilter.toLowerCase();
    return matchesSearch && matchesStatus;
  });

  const handleSelectAll = (e) => {
    if (e.target.checked) {
      setSelectedBookings(filteredBookings.map(b => b.id));
    } else {
      setSelectedBookings([]);
    }
  };

  const handleSelectBooking = (id) => {
    if (selectedBookings.includes(id)) {
      setSelectedBookings(selectedBookings.filter(b => b !== id));
    } else {
      setSelectedBookings([...selectedBookings, id]);
    }
  };

  const handleStatusChange = (id, newStatus) => {
    setBookings(bookings.map(b => {
      if (b.id === id) {
        return { ...b, status: newStatus };
      }
      return b;
    }));
  };

  const handleDeleteBooking = (id) => {
    setBookings(bookings.filter(b => b.id !== id));
  };

  const totalBookings = bookings.length;
  const completedBookings = bookings.filter(b => b.status === 'Completed').length;
  const cancelledBookings = bookings.filter(b => b.status === 'Cancelled').length;
  const returnedBookings = bookings.filter(b => b.status === 'Returned').length;
  const totalRevenue = bookings.reduce((sum, b) => sum + b.revenue, 0);

  return (
    <div style={styles.container}>
      <AdminNavbar />
      <AdminSidebar />
      
      <main style={styles.mainContent}>
        <div style={styles.contentWrapper}>
          <h2 style={styles.pageTitle}>Manage Bookings</h2>

          {/* Summary Cards */}
          <div style={styles.summaryCards} aria-label="Booking summary">
            <div style={styles.card} aria-label={`${totalBookings} total bookings`}>
              <div style={styles.iconContainer}>
                <svg viewBox="0 0 24 24" style={styles.iconSvg}>
                  <path d="M3 10h18v7a3 3 0 0 1-3 3H6a3 3 0 0 1-3-3v-7z" fill="white"/>
                </svg>
              </div>
              <div style={styles.cardText}>
                <div style={styles.cardValue}>{totalBookings} <span style={styles.cardDesc}>Total Bookings</span></div>
              </div>
            </div>
            <div style={{...styles.card, ...styles.cardSuccess}} aria-label={`${completedBookings} completed bookings`}>
              <div style={{...styles.iconContainer, backgroundColor: '#55994c'}}>
                <svg viewBox="0 0 24 24" style={styles.iconSvg}>
                  <path d="M9 12l2 2 4-4" stroke="white" strokeWidth="2" fill="none" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
              </div>
              <div style={styles.cardText}>
                <div style={styles.cardValue}>{completedBookings} <span style={styles.cardDesc}>Completed</span></div>
              </div>
            </div>
            <div style={{...styles.card, ...styles.cardWarning}} aria-label={`${cancelledBookings} cancelled bookings`}>
              <div style={{...styles.iconContainer, backgroundColor: '#c43333'}}>
                <svg viewBox="0 0 24 24" style={styles.iconSvg}>
                  <path d="M18 6 6 18M6 6l12 12" stroke="white" strokeWidth="2" fill="none" strokeLinecap="round"/>
                </svg>
              </div>
              <div style={styles.cardText}>
                <div style={styles.cardValue}>{cancelledBookings} <span style={styles.cardDesc}>Cancelled</span></div>
              </div>
            </div>
            <div style={{...styles.card, ...styles.cardInfo}} aria-label={`₱${totalRevenue} total revenue`}>
              <div style={{...styles.iconContainer, backgroundColor: '#f79726'}}>
                <svg viewBox="0 0 24 24" style={styles.iconSvg}>
                  <path d="M12 3v18M7 8h10M7 16h10" stroke="white" strokeWidth="2" fill="none" strokeLinecap="round"/>
                </svg>
              </div>
              <div style={styles.cardText}>
                <div style={styles.cardValue}>₱{totalRevenue.toLocaleString()}</div>
                <div style={styles.cardDesc}>Total Revenue</div>
              </div>
            </div>
          </div>

          {/* Filter Row */}
          <div style={styles.filterRow} role="search" aria-label="Filters and search bookings">
            <select 
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
              style={styles.select}
              aria-label="Filter by status"
            >
              <option value="">All Status</option>
              <option value="Completed">Completed</option>
              <option value="Cancelled">Cancelled</option>
              <option value="Returned">Returned</option>
            </select>
            <input 
              type="search" 
              placeholder="Search by user, car or ID..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              style={styles.searchInput}
              aria-label="Search bookings"
            />
          </div>

          {/* Table */}
          <div style={styles.tableContainer}>
            <table style={styles.table}>
              <thead>
                <tr>
                  <th style={{...styles.th, ...styles.checkboxCell}}>
                    <input 
                      type="checkbox" 
                      checked={selectedBookings.length === filteredBookings.length && filteredBookings.length > 0}
                      onChange={handleSelectAll}
                      aria-label="Select all bookings"
                    />
                  </th>
                  <th style={styles.th}>User</th>
                  <th style={styles.th}>Car</th>
                  <th style={styles.th}>Booking Dates</th>
                  <th style={styles.th}>Revenue</th>
                  <th style={styles.th}>Status</th>
                  <th style={{...styles.th, ...styles.actionsCell}}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredBookings.map(booking => (
                  <tr key={booking.id} style={styles.tr}>
                    <td style={{...styles.td, ...styles.checkboxCell}}>
                      <input 
                        type="checkbox" 
                        checked={selectedBookings.includes(booking.id)}
                        onChange={() => handleSelectBooking(booking.id)}
                        aria-label={`Select booking ${booking.id}`}
                      />
                    </td>
                    <td style={styles.td}>{booking.user}</td>
                    <td style={styles.td}>{booking.car}</td>
                    <td style={styles.td}>{booking.dates}</td>
                    <td style={{...styles.td, ...styles.revenueCell}}>₱{booking.revenue.toLocaleString()}.00</td>
                    <td style={{...styles.td, ...styles.statusCell}}>
                      <span style={{
                        ...styles.statusBadge,
                        ...(booking.status === 'Completed' ? styles.statusCompleted : 
                           booking.status === 'Cancelled' ? styles.statusCancelled : styles.statusReturned)
                      }}>
                        {booking.status}
                      </span>
                    </td>
                    <td style={{...styles.td, ...styles.actionsCell}}>
                      {booking.status !== 'Completed' && (
                        <button 
                          style={styles.actionBtn}
                          onClick={() => handleStatusChange(booking.id, 'Completed')}
                          aria-label={`Mark as Completed`}
                          title="Mark as Completed"
                        >
                          ✅
                        </button>
                      )}
                      {booking.status !== 'Cancelled' && (
                        <button 
                          style={styles.actionBtn}
                          onClick={() => handleStatusChange(booking.id, 'Cancelled')}
                          aria-label={`Mark as Cancelled`}
                          title="Mark as Cancelled"
                        >
                          ❌
                        </button>
                      )}
                      {booking.status !== 'Returned' && (
                        <button 
                          style={styles.actionBtn}
                          onClick={() => handleStatusChange(booking.id, 'Returned')}
                          aria-label={`Mark as Returned`}
                          title="Mark as Returned"
                        >
                          🔄
                        </button>
                      )}
                      <button 
                        style={styles.actionBtn}
                        onClick={() => handleDeleteBooking(booking.id)}
                        aria-label={`Delete booking`}
                        title="Delete"
                      >
                        🗑️
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* Info Row */}
          <section style={styles.infoRow} aria-label="Benefits of using car rental system">
            <div style={styles.infoBox}>
              <svg viewBox="0 0 64 64" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinejoin="round" strokeLinecap="round" style={styles.infoSvg}>
                <path d="M9 52h46M12 44h40M16 36h32M20 28h24M24 20h16"/>
              </svg>
              <div style={styles.infoText}>
                <strong>Affordable Rates</strong>
                <span>Great prices on all vehicle types</span>
              </div>
            </div>
            <div style={styles.infoBox}>
              <svg viewBox="0 0 50 50" fill="none" stroke="currentColor" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" style={styles.infoSvg}>
                <circle cx="25" cy="25" r="24" />
                <path d="M21 18v9l6 3" />
                <path d="M25 31v-8" />
                <path d="M15 15h20" />
                <path d="M12 38h10" />
                <path d="M33 38h7" />
              </svg>
              <div style={styles.infoText}>
                <strong>Safety &amp; Security</strong>
                <span>Well-maintained and safe rental cars</span>
              </div>
            </div>
            <div style={styles.infoBox}>
              <svg viewBox="0 0 22 22" fill="none" stroke="currentColor" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" style={styles.infoSvg}>
                <path d="M2 16v1a5 5 0 0 0 10 0v-1" />
                <path d="M17 12v-6a5 5 0 0 0-10 0v6" />
                <line x1="0" y1="7" x2="22" y2="7" />
                <line x1="4" y1="12" x2="18" y2="12" />
                <line x1="7" y1="16" x2="15" y2="16" />
              </svg>
              <div style={styles.infoText}>
                <strong>Easy Booking</strong>
                <span>Quick and Hassle free online reservations</span>
              </div>
            </div>
          </section>
        </div>
      </main>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inria+Serif&display=swap');
        
        * { box-sizing: border-box; }
      `}</style>
    </div>
  );
};

